#! /bin/sh

# curl -L https://sourcegraph.com/.api/src-cli/src_darwin_amd64 -o src
# chmod +x src

# Get the path_repository argument
path_repository="$1"

src search -json 'context:global "alpaca_eval" case:yes select:repo count:all' >"${path_repository}/AlpacaEval.json"
src search -json 'context:global /import\s+ares|from\s+ares(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/ARES.json"
src search -json 'context:global /python(\d+(\.\d+)?)?\s+runbenchmark\.py/ case:yes select:repo count:all' >"${path_repository}/AutoML Benchmark.json"
src search -json 'context:global /import\s+bananalyzer|from\s+bananalyzer(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Banana-lyzer.json"
src search -json 'context:global /bigcode_eval|bigcode-project\/evaluation-harness/ case:yes select:repo count:all' >"${path_repository}/Code Generation LM Evaluation Harness.json"
src search -json 'context:global "evalai" case:yes select:repo count:all' >"${path_repository}/EvalAI.json"
src search -json 'context:global /oaieval|import\s+evals|from\s+evals(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Evals.json"
src search -json 'context:global /python(\d+(\.\d+)?)?\s+(evalscope|llmuses)\/run\.py|import\s+(evalscope|llmuses)|from\s+(evalscope|llmuses)(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/EvalScope.json"
src search -json 'context:global "evalverse" case:yes select:repo count:all' >"${path_repository}/Evalverse.json"
src search -json 'context:global /evidently\s+ui|import\s+evidently|from\s+evidently(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Evidently.json"
src search -json 'context:global /import\s+flageval|from\s+flageval(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/FlagEval.json"
src search -json 'context:global "fmbench" case:yes select:repo count:all' >"${path_repository}/FMBench.json"
src search -json 'context:global /scripts\/(generate_test_cases|merge_test_cases|generate_completions|evaluate_completions|step1(\.5)?|step2|step3)\.sh|python(\d+(\.\d+)?)?\s+\.\/scripts\/run_pipeline\.py/ case:yes select:repo count:all' >"${path_repository}/HarmBench.json"
src search -json 'context:global "crfm-helm" case:yes select:repo count:all' >"${path_repository}/HELM.json"
src search -json 'context:global "inspect-ai" case:yes select:repo count:all' >"${path_repository}/Inspect.json"
src search -json 'context:global /import\s+intercode|from\s+intercode(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/InterCode.json"
src search -json 'context:global "lm_eval" case:yes select:repo count:all' >"${path_repository}/Language Model Evaluation Harness.json"
src search -json 'context:global /lighteval\s+(accelerate|nanotron)|python(\d+(\.\d+)?)?\s+run_evals_accelerate\.py|import\s+lighteval|from\s+lighteval(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/LightEval.json"
src search -json 'context:global "llm-autoeval" case:yes select:repo count:all' >"${path_repository}/LLM AutoEval.json"
src search -json 'context:global /python(\d+(\.\d+)?)?\s+(run_benchmark|llm_correctness)\.py|import\s+llmperf|from\s+llmperf(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/LLMPerf.json"
src search -json 'context:global "lmms-eval" case:yes select:repo count:all' >"${path_repository}/lmms-eval.json"
src search -json 'context:global "cm run script" case:yes select:repo count:all' >"${path_repository}/MLPerf Inference.json"
src search -json 'context:global "olmo_eval" case:yes select:repo count:all' >"${path_repository}/OLMo-Eval.json"
src search -json 'context:global "opencompass" case:yes select:repo count:all' >"${path_repository}/OpenCompass.json"
src search -json 'context:global /import\s+opik|from\s+opik(\.\w+)?\s+import |comet-ml\/opik\/opik-(backend|frontend)/ case:yes select:repo count:all' >"${path_repository}/Opik.json"
src search -json 'context:global /optimum-benchmark|import\s+optimum_benchmark|from\s+optimum_benchmark(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Optimum-Benchmark.json"
src search -json 'context:global /import\s+phasellm|from\s+phasellm(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/PhaseLLM.json"
src search -json 'context:global /arize-phoenix|arizephoenix\/phoenix/ case:yes select:repo count:all' >"${path_repository}/Phoenix.json"
src search -json 'context:global /import\s+prometheus_eval|from\s+prometheus_eval(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Prometheus-Eval.json"
src search -json 'context:global /import\s+promptbench|from\s+promptbench(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/PromptBench.json"
src search -json 'context:global /ragchecker-cli|import\s+ragchecker|from\s+ragchecker(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/RAGChecker.json"
src search -json 'context:global /import\s+rageval|from\s+rageval(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Rageval.json"
src search -json 'context:global /refchecker-cli|import\s+refchecker|from\s+refchecker(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/RefChecker.json"
src search -json 'context:global "rewardbench" case:yes select:repo count:all' >"${path_repository}/RewardBench.json"
src search -json 'context:global /import\s+tensorflow_model_analysis|from\s+tensorflow_model_analysis(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/TensorFlow Model Analysis.json"
src search -json 'context:global /import\s+tonic_validate|from\s+tonic_validate(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/Tonic Validate.json"
src search -json 'context:global /import\s+trulens|from\s+trulens(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/TruLens.json"
src search -json 'context:global /import\s+trustllm|from\s+trustllm(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/TrustLLM.json"
src search -json 'context:global /run_uptrain\.sh|import\s+uptrain|from\s+uptrain(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/UpTrain.json"
src search -json 'context:global "vbench" case:yes select:repo count:all' >"${path_repository}/VBench.json"
src search -json 'context:global /import\s+vlmeval|from\s+vlmeval(\.\w+)?\s+import / case:yes select:repo count:all' >"${path_repository}/VLMEvalKit.json"

github-dependents-info --repo confident-ai/deepeval -p -j >"${path_repository}/DeepEval.json"
github-dependents-info --repo huggingface/evaluate -p -j >"${path_repository}/Evaluate.json"
github-dependents-info --repo embeddings-benchmark/mteb -p -j >"${path_repository}/MTEB.json"
github-dependents-info --repo explodinggradients/ragas -p -j >"${path_repository}/Ragas.json"
